INSERT INTO movie (title, director, rate, release_date, synopsis, image)
VALUES ('Le dernier combat', 'Damien Lugagne-Delpon', 4.9, '2033-12-01',
        'Clément n''était qu''un simple supporter passionné, jusqu''au jour où le destin — et une explosion nucléaire tactique sur les quais de Paris — en a décidé autrement. Quand une organisation paramilitaire secrète menace d''effacer l''histoire du football et de conquérir le monde, Clément n''a d''autre choix que d''enfiler son maillot  PSG Fourth 2024/2025 (édition limitée, évidemment) pour rétablir la justice. Le match est fini quand je décide qu''il est fini. Et je viens juste de demander le temps additionnel.',
        'image_film_7.png');

INSERT INTO movie (title, director, rate, release_date, synopsis, image)
VALUES ('La Mystérieuse Majeure MTI', 'Xavier de Choudens', 4.85, '2026-09-01',
        'Inspirée par la célèbre série d''animation, cette aventure suit un groupe d''étudiants de l''EPITA lancés dans la quête du savoir ultime. Entre cours d''architecture système et quêtes légendaires, ils devront percer les secrets du Multimédia et des Technologies de l''Information pour sauver leur semestre.',
        'image_film_11.png');

INSERT INTO movie (title, director, rate, release_date, synopsis, image)
VALUES ('Les Deux Boulles d''un mec', 'Pierre Ramasse-Tout', 3.92, '2025-06-18',
        'Un étudiant en fin de cycle décide de tout plaquer pour devenir champion de pétanque au Vieux-Port. Une épopée marseillaise où la loose est temporaire, mais où le pastis et les boules sont sacrés. Un film sur l''amitié, le soleil et l''art de pointer ou tirer.',
        'image_film_10.png');

INSERT INTO movie (title, director, rate, release_date, synopsis, image)
VALUES ('JAWS : L''étudiant du fond', 'Steven Spielberg', 4.15, '2026-01-15',
        'Alors que la piscine de l''école semble calme, une menace silencieuse émerge des profondeurs du code source. Un étudiant, resté trop longtemps en mode "piscine" C, finit par se fondre dans l''élément liquide. La terreur ne vient plus de la mer, mais de celui qui a trop compilé.',
        'image_film_8.png');
